972	  \[
973	    \HModulePrime\,k\,(\Scheme.\toModuleKSheaf\,C)\,n\,(S.\mathtt{toMayerVietorisSquare}.\mathtt{toSquare}.X_4)
974	    \;\equiv_{\Module k}\;
975	    \HModule\,k\,(\Scheme.\toModuleKSheaf\,C)\,n.
976	  \]
